import{_ as a,a as t,b as i,c as o,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as n,c as d,a2 as c}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Aggiungere un canale Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/telegram.md","filePath":"it-IT/upload/telegram.md","lastUpdated":1781962217000}'),s={name:"it-IT/upload/telegram.md"};function p(g,e,m,h,u,b){return n(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="aggiungere-un-canale-telegram" tabindex="-1">Aggiungere un canale Telegram <a class="header-anchor" href="#aggiungere-un-canale-telegram" aria-label="Permalink to &quot;Aggiungere un canale Telegram&quot;">​</a></h1><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>A cosa serve</th></tr></thead><tbody><tr><td>Account Telegram</td><td>Per creare il bot e il canale di archiviazione.</td></tr><tr><td><code>@BotFather</code></td><td>Per creare un bot Telegram.</td></tr><tr><td>Canale Telegram</td><td>Destinazione finale dei file.</td></tr><tr><td><code>@userinfobot</code></td><td>Per recuperare il <code>Chat ID</code> del canale.</td></tr></tbody></table><h2 id="dove-aggiungerlo" tabindex="-1">Dove aggiungerlo <a class="header-anchor" href="#dove-aggiungerlo" aria-label="Permalink to &quot;Dove aggiungerlo&quot;">​</a></h2><ol><li>Apri Impostazioni di sistema.</li><li>Vai a Impostazioni di caricamento.</li><li>Clicca su Aggiungi canale in alto a destra.</li><li>Seleziona <code>Telegram</code>.</li></ol><h2 id="riferimento-campi" tabindex="-1">Riferimento campi <a class="header-anchor" href="#riferimento-campi" aria-label="Permalink to &quot;Riferimento campi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Funzione</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>Nome canale</td><td>Nome riconoscibile, per esempio <code>Telegram Primary</code>.</td><td>Sì</td></tr><tr><td>Attivo</td><td>Abilita o disabilita il canale.</td><td>Consigliato</td></tr><tr><td>Bot Token</td><td>Token del bot Telegram.</td><td>Sì</td></tr><tr><td>Session ID (Chat ID)</td><td>ID del canale Telegram.</td><td>Sì</td></tr><tr><td>Relay Proxy URL (opzionale)</td><td>Da usare solo se l&#39;accesso a Telegram è instabile. Inserisci l&#39;URL completo con <code>https://</code>.</td><td>No</td></tr><tr><td>Nota</td><td>Appunti per manutenzione futura.</td><td>No</td></tr></tbody></table><h2 id="configurazione" tabindex="-1">Configurazione <a class="header-anchor" href="#configurazione" aria-label="Permalink to &quot;Configurazione&quot;">​</a></h2><h3 id="_1-crea-un-bot-telegram" tabindex="-1">1. Crea un bot Telegram <a class="header-anchor" href="#_1-crea-un-bot-telegram" aria-label="Permalink to &quot;1. Crea un bot Telegram&quot;">​</a></h3><ol><li>Apri Telegram e cerca <code>@BotFather</code>.</li><li>Apri la chat e clicca su <code>Start</code>.</li><li>Invia <code>/newbot</code>.</li><li>Segui le istruzioni e inserisci il nome visualizzato del bot.</li><li>Inserisci poi lo username del bot. Di solito deve terminare con <code>bot</code>.</li><li>Dopo la creazione, <code>@BotFather</code> restituisce un bot token.</li></ol><p>Questo token è il <code>Bot Token</code> da inserire in ImgBed.</p><p><img src="'+a+'" alt="Salva Bot Token" loading="lazy"></p><h3 id="_2-crea-un-canale" tabindex="-1">2. Crea un canale <a class="header-anchor" href="#_2-crea-un-canale" aria-label="Permalink to &quot;2. Crea un canale&quot;">​</a></h3><ol><li>In Telegram clicca su Nuovo canale.</li><li>Inserisci il nome del canale.</li><li>Completa la creazione.</li></ol><p>Puoi usare sia canali pubblici sia privati.</p><p><img src="'+t+'" alt="Crea canale" loading="lazy"></p><h3 id="_3-aggiungi-il-bot-al-canale" tabindex="-1">3. Aggiungi il bot al canale <a class="header-anchor" href="#_3-aggiungi-il-bot-al-canale" aria-label="Permalink to &quot;3. Aggiungi il bot al canale&quot;">​</a></h3><ol><li>Apri il canale appena creato.</li><li>Apri le impostazioni del canale.</li><li>Aggiungi un membro o un amministratore.</li><li>Cerca lo username del bot creato.</li><li>Aggiungi il bot al canale.</li></ol><p>Per upload più affidabili, concedi al bot permessi di amministratore.</p><p><img src="'+i+'" alt="Invita il bot nel canale" loading="lazy"></p><h3 id="_4-recupera-channel-id-con-user-info-get-id-idbot" tabindex="-1">4. Recupera Channel ID con User Info - Get ID - IDbot <a class="header-anchor" href="#_4-recupera-channel-id-con-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Recupera Channel ID con User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Cerca <code>@userinfobot</code> in Telegram. Il nome visualizzato di solito è <code>User Info - Get ID - IDbot</code>.</li><li>Apri la chat e clicca su <code>Start</code>.</li><li>Scegli <code>Channel</code> tra le opzioni del bot.</li><li>Nel selettore messaggi, scegli il canale di destinazione e invialo a <code>@userinfobot</code>.</li><li>Quando <code>@userinfobot</code> restituisce il risultato, copia il numero indicato come <code>Id: -100...</code>.</li></ol><p>Il numero che inizia con <code>-100</code> è la <code>Session ID (Chat ID)</code> richiesta da ImgBed.</p><p><img src="'+o+'" alt="Recupera Channel ID" loading="lazy"></p><h3 id="_5-compila-il-canale-telegram-in-imgbed" tabindex="-1">5. Compila il canale Telegram in ImgBed <a class="header-anchor" href="#_5-compila-il-canale-telegram-in-imgbed" aria-label="Permalink to &quot;5. Compila il canale Telegram in ImgBed&quot;">​</a></h3><p>Torna alla finestra di configurazione e compila:</p><table tabindex="0"><thead><tr><th>Campo UI</th><th>Valore</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Nome personalizzato, per esempio <code>TelegramPrimary</code>.</td></tr><tr><td>Attivo</td><td>Consigliato.</td></tr><tr><td>Bot Token</td><td>Il token ottenuto da <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Il numero <code>-100...</code> restituito da <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (opzionale)</td><td>Solo se serve, per esempio <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Nota</td><td>Note opzionali.</td></tr></tbody></table><p>Quando hai finito, salva.</p><p><img src="'+l+`" alt="Modifica configurazione" loading="lazy"></p><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Controllo</th><th>Come verificare</th></tr></thead><tbody><tr><td>Scheda canale</td><td>Dopo il salvataggio compare una scheda Telegram.</td></tr><tr><td>Canale abilitabile</td><td>L&#39;interruttore Attivo resta acceso.</td></tr><tr><td>Configurazione salvata</td><td>La vista dettaglio mostra Bot Token e Chat ID salvati.</td></tr><tr><td>Upload funzionante</td><td>Carica un&#39;immagine di prova e verifica che compaia nel canale Telegram di destinazione.</td></tr></tbody></table><h2 id="checklist-rapida" tabindex="-1">Checklist rapida <a class="header-anchor" href="#checklist-rapida" aria-label="Permalink to &quot;Checklist rapida&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Crea un bot con @BotFather</span></span>
<span class="line"><span>-&gt; Salva il Bot Token</span></span>
<span class="line"><span>-&gt; Crea un canale Telegram</span></span>
<span class="line"><span>-&gt; Aggiungi il bot al canale e concedi permessi di amministratore</span></span>
<span class="line"><span>-&gt; Cerca @userinfobot e scegli Channel</span></span>
<span class="line"><span>-&gt; Inoltra un messaggio del canale a @userinfobot</span></span>
<span class="line"><span>-&gt; Copia Id: -100...</span></span>
<span class="line"><span>-&gt; Inserisci Bot Token e Chat ID in ImgBed</span></span>
<span class="line"><span>-&gt; Salva e carica un&#39;immagine di prova</span></span></code></pre></div><h2 id="riferimenti" tabindex="-1">Riferimenti <a class="header-anchor" href="#riferimenti" aria-label="Permalink to &quot;Riferimenti&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const _=r(s,[["render",p]]);export{C as __pageData,_ as default};
